async function seed() {
  if (!process.env.SUPABASE_SECRET_KEY) {
    console.error('Missing SUPABASE_SECRET_KEY — add it to .env')
    process.exit(1)
  }
  console.log(`Seeding ${bills.length} bills…`)
  const { error } = await supabase
    .from('bills')
    .upsert(bills, { onConflict: 'id' })
  if (error) {
    console.error('Seed failed:', error.message)
    process.exit(1)
  }
  console.log(`✅ Seeded ${bills.length} bills successfully.`)
  process.exit(0)
}

seed().catch(err => { console.error(err); process.exit(1) })
